export type CustomerStatus = "VIP" | "standard";

export interface Customer {
  status: CustomerStatus;
}

/**
 * Calculates the discount amount for a given customer and order total.
 *
 * Rules (in priority order):
 *  1. VIP customers with order total > 150 receive a 15% volume discount
 *     (volume rate overrides the standard VIP rate).
 *  2. VIP customers with order total ≤ 150 receive a 20% discount.
 *  3. Standard customers receive no discount regardless of order total.
 *
 * @param customer  - The customer object containing status information.
 * @param orderTotal - The total value of the order (must be >= 0).
 * @returns The discount amount (not the discounted price).
 */
export function calculateDiscount(customer: Customer, orderTotal: number): number {
  if (customer.status === "VIP" && orderTotal > 150) {
    // Volume discount: 15% — overrides VIP rate for large orders (AC4, AC5)
    return orderTotal * 0.15;
  }

  if (customer.status === "VIP") {
    // Standard VIP discount: 20% (AC1, AC2)
    return orderTotal * 0.2;
  }

  // Standard customers receive no discount (AC3)
  return 0;
}
---
import { calculateDiscount, Customer } from "./discountEngine";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------
const vip: Customer = { status: "VIP" };
const standard: Customer = { status: "standard" };

// ---------------------------------------------------------------------------
// Bird's Acceptance Criteria
// ---------------------------------------------------------------------------
describe("calculateDiscount — Bird's acceptance criteria", () => {
  // AC1
  it("AC1: VIP customer with order total 100 receives a 20 discount (20%)", () => {
    expect(calculateDiscount(vip, 100)).toBe(20);
  });

  // AC2
  it("AC2: VIP customer with order total 50 receives a 10 discount (20%)", () => {
    expect(calculateDiscount(vip, 50)).toBe(10);
  });

  // AC3
  it("AC3: Standard customer with order total 200 receives no discount", () => {
    expect(calculateDiscount(standard, 200)).toBe(0);
  });

  // AC4 — boundary: standard customer at 151 still gets 0 (volume is VIP-only);
  //         VIP customer at 151 switches to 15%
  it("AC4: Order total above 150 applies 15% volume discount for VIP customers", () => {
    expect(calculateDiscount(vip, 151)).toBeCloseTo(151 * 0.15);
  });

  // AC5
  it("AC5: VIP customer with order total 200 receives a 30 discount (15% volume discount)", () => {
    expect(calculateDiscount(vip, 200)).toBe(30);
  });
});

// ---------------------------------------------------------------------------
// Edge & boundary cases
// ---------------------------------------------------------------------------
describe("calculateDiscount — edge cases", () => {
  it("VIP at the volume boundary (150) still uses the 20% VIP rate", () => {
    expect(calculateDiscount(vip, 150)).toBe(30); // 150 * 0.20
  });

  it("VIP at 150.01 crosses into volume discount territory (15%)", () => {
    expect(calculateDiscount(vip, 150.01)).toBeCloseTo(150.01 * 0.15);
  });

  it("Standard customer with order total 0 receives no discount", () => {
    expect(calculateDiscount(standard, 0)).toBe(0);
  });

  it("Standard customer with order total 151 still receives no discount (AC3/AC4 clarification)", () => {
    expect(calculateDiscount(standard, 151)).toBe(0);
  });

  it("VIP customer with order total 0 receives no discount", () => {
    expect(calculateDiscount(vip, 0)).toBe(0);
  });
});

